// Chaque type de rapport a son fichier tpl-xxx.js indépendant
function _getTemplate(docType) {
  var map = {
    'audit':             window.TPL_AUDIT_PICO,
    'doe':               window.TPL_DOE_PICO,
    'antenne':           window.TPL_ANTENNE,
    'doe_antenne':       window.TPL_DOE_ANTENNE,
    'antenne_doe':       window.TPL_DOE_ANTENNE,
    'audit_celfi':       window.TPL_CELFI,
    'doe_celfi':         window.TPL_DOE_CELFI,
    'audit_wifi':        window.TPL_WIFI,
    'audit_starlink':    window.TPL_STARLINK,
    'audit_cradlepoint': window.TPL_CRADLEPOINT,
  };
  return map[docType] || window.TPL_AUDIT_PICO;
}

