// Lit une valeur depuis le template JSON si disponible
function _tpl(docType, path, fallback) {
  var t = window.PDF_TEMPLATES && window.PDF_TEMPLATES[docType];
  if (!t) return fallback;
  var parts = path.split('.');
  var val = t;
  for (var i=0; i<parts.length; i++) {
    if (val == null) return fallback;
    val = val[parts[i]];
  }
  return (val !== undefined && val !== null) ? val : fallback;
}

// Convertit un hex color en objet {r,g,b} pour PDFLib.rgb()
function _hexToRgb(hex) {
  if (!hex) return null;
  hex = hex.replace('#','');
  return {
    r: parseInt(hex.substr(0,2),16)/255,
    g: parseInt(hex.substr(2,2),16)/255,
    b: parseInt(hex.substr(4,2),16)/255,
  };
}

function _u8(b64){const s=atob(b64),u=new Uint8Array(s.length);for(let i=0;i<s.length;i++)u[i]=s.charCodeAt(i);return u;}
function _s2(v){if(v==null)return'';return String(v).trim();}
function _s2max(v,n){var s=_s2(v);return s.length>n?s.substring(0,n-1)+'..':s;}

async function _embedImg(doc, b64) {
  if (!b64) return null;
  try {
    if (b64.includes('image/jpeg') || b64.includes('image/jpg')) return await doc.embedJpg(_u8(b64.split(',')[1]));
    if (b64.includes('image/png'))  return await doc.embedPng(_u8(b64.split(',')[1]));
    return await doc.embedJpg(_u8(b64.split(',')[1]));
  } catch(e) { return null; }
}

/* ── Couleur fond selon RSRP ────────────────────────────────────── */
function _rsrpRgb(rsrp, rgb) {
  var v = parseInt(rsrp || '');
  if (isNaN(v)) return rgb(0.04,0.08,0.16);
  if (v >= -97)  return rgb(0.01,0.18,0.05);
  if (v >= -107) return rgb(0.18,0.14,0.01);
  if (v >= -117) return rgb(0.18,0.07,0.01);
  return rgb(0.18,0.02,0.02);
}

/* ═══════════════════════════════════════════════════════════════════
   ENTRÉE PRINCIPALE
=================================================================== */
async function generatePDF(data) {
  var docType = data.docType || 'audit';
  if (docType === 'antenne')                                     return _renderAntenneAudit(data);
  if (docType === 'doe_antenne' || docType === 'antenne_doe')    return _renderAntenneDOE(data);
  if (docType === 'audit_celfi'  || docType === 'doe_celfi')     return _renderCelfi(data);
  if (docType === 'audit_wifi')                                  return _renderWifi(data);
  if (docType === 'audit_starlink' || docType === 'audit_cradlepoint') return _renderStarlink(data);
  if (docType === 'doe')         return _renderPicoDOE(data);
  return _renderPicoAudit(data);
}

