async function _makeCtx(title, filename, data) {
  var { PDFDocument, StandardFonts, rgb } = PDFLib;
  var doc = await PDFDocument.create();
  var fR = await doc.embedFont(StandardFonts.Helvetica);
  var fB = await doc.embedFont(StandardFonts.HelveticaBold);
  var fI = await doc.embedFont(StandardFonts.HelveticaOblique);
  var W=595.28, H=841.89, ML=50, MR=545, CW=MR-ML;
  var WHITE=rgb(1,1,1), BLACK=rgb(0,0,0);
  var BY=rgb(0,0.357,0.733);          // Bleu Bouygues #005bbb
  var BL=BY, DB=rgb(0,0.15,0.33);
  var LG=rgb(0.93,0.93,0.93), GREY=rgb(0.45,0.50,0.56);
  var GREEN=rgb(0.02,0.50,0.17), RED=rgb(0.75,0.08,0.08);
  var ORANGE=rgb(0.96,0.37,0);
  var g = data.garde || {};
  var p = null;
  var y = 0;

  function newPage() {
    p = doc.addPage([W,H]);
    // Bande latérale gauche
    p.drawRectangle({x:0,y:0,width:32,height:H,color:DB});
    y = H-55;
    return p;
  }

  function sectionTitle(num, txt) {
    if (y < 100) { newPage(); }
    p.drawRectangle({x:ML,y:y-22,width:CW,height:28,color:rgb(0.04,0.10,0.22)});
    p.drawText(num+'.', {x:ML+6,y:y-13,size:10,font:fB,color:BL});
    p.drawText(_s2(txt), {x:ML+26,y:y-13,size:11,font:fB,color:WHITE});
    p.drawLine({start:{x:ML,y:y-22},end:{x:MR,y:y-22},thickness:0.5,color:BL});
    y -= 38;
  }

  function field(lbl, val, indent) {
    if (y < 60) { newPage(); }
    var x = ML + (indent||0);
    p.drawText(_s2(lbl), {x:x,y:y,size:9,font:fI,color:GREY});
    p.drawText(_s2max(val,80), {x:x+130,y:y,size:9,font:fB,color:BLACK});
    y -= 16;
  }

  function textBlock(txt, opts) {
    var maxW = (opts && opts.maxW) || 90;
    var col   = (opts && opts.color) || BLACK;
    var x     = ML + ((opts && opts.indent) || 0);
    if (!txt || !_s2(txt)) return;
    var lines = _s2(txt).match(new RegExp('.{1,'+maxW+'}','g')) || [];
    lines.slice(0, opts && opts.maxLines || 20).forEach(function(l){
      if (y < 60) { newPage(); }
      p.drawText(l, {x:x,y:y,size:9,font:fR||fR,color:col});
      y -= 14;
    });
  }

  function coverPage() {
    newPage();
    // Logo placeholder area
    p.drawRectangle({x:MR-160,y:H-80,width:130,height:50,color:rgb(0.04,0.10,0.22)});
    p.drawText('BOUYGUES', {x:MR-145,y:H-48,size:10,font:fB,color:BL});
    p.drawText('TELECOM', {x:MR-141,y:H-62,size:9,font:fI,color:WHITE});
    // Titre
    p.drawRectangle({x:ML,y:H-180,width:CW,height:60,color:rgb(0.04,0.10,0.22)});
    p.drawText(title, {x:ML+14,y:H-152,size:20,font:fB,color:WHITE});
    p.drawLine({start:{x:ML,y:H-182},end:{x:MR,y:H-182},thickness:2,color:BL});
    // Infos chantier
    y = H-220;
    field('Numéro OT :',      g.ot);
    field('Raison sociale :',  g.raisonSociale);
    field('Adresse :',         g.adresse);
    field('Contact :',         g.contact);
    field('Téléphone :',       g.telephone);
    field('Technicien :',      g.technicien);
    field('Date :',            g.date);
    // Photo principale
    return _embedImg(doc, g.photoPrincipale);
  }

  function download(fname) {
    doc.save().then(function(bytes){
      var blob = new Blob([bytes],{type:'application/pdf'});
      var url  = URL.createObjectURL(blob);
      var a    = document.createElement('a');
      a.href   = url;
      a.download= fname+'_'+(_s2(g.ot)||'Export')+'.pdf';
      a.click();
    });
  }

  return { doc, fR, fB, fI, W, H, ML, MR, CW, WHITE, BLACK, BL, DB, LG,
           GREY, GREEN, RED, ORANGE, rgb, g, p, get_p:function(){return p;}, get_y:function(){return y;},
           newPage, sectionTitle, field, textBlock, coverPage, download,
           set_p:function(np){p=np;}, set_y:function(ny){y=ny;},
           _embedImg: function(b){return _embedImg(doc,b);} };
}

