  y -= 8;
  // ── Images fixes JAUGE (gauche) + SPEEDTEST (droite) ────────────────────
  var oth=160, otw=(CW/2)-10;
  // Image fixe gauche : JAUGE signal (Network Cell Info Lite)
  // ── Images JAUGE (gauche, flush-right) + SPEEDTEST (droite, flush-left) ──
  var gap2 = 10;
  var halfW = (CW - gap2) / 2;

  // JAUGE — alignée à droite de sa moitié (contre SPEEDTEST)
  try {
    var imgFixG = await doc.embedJpg(_u8(_IMG_JAUGE_B64));
    var scG = Math.min(halfW/imgFixG.width, oth/imgFixG.height);
    var gw = imgFixG.width*scG, gh = imgFixG.height*scG;
    p.drawImage(imgFixG, {x: ML+halfW-gw, y:y-oth, width:gw, height:gh});
  } catch(e) {
    p.drawRectangle({x:ML, y:y-oth, width:halfW, height:oth, color:rgb(0.05,0.08,0.18)});
    p.drawText('JAUGE signal', {x:ML+halfW/2-28, y:y-oth/2, size:9, font:fB, color:GREY});
  }

  // SPEEDTEST — alignée à gauche de sa moitié (contre JAUGE)
  try {
    var imgFixD = await doc.embedJpg(_u8(_IMG_SPEEDTEST_B64));
    var scD = Math.min(halfW/imgFixD.width, oth/imgFixD.height);
    var dw2 = imgFixD.width*scD, dh = imgFixD.height*scD;
    p.drawImage(imgFixD, {x: ML+halfW+gap2, y:y-oth, width:dw2, height:dh});
  } catch(e) {
    p.drawRectangle({x:ML+halfW+gap2, y:y-oth, width:halfW, height:oth, color:rgb(0.05,0.08,0.18)});
    p.drawText('SPEEDTEST debit', {x:ML+halfW+gap2+halfW/2-36, y:y-oth/2, size:9, font:fB, color:GREY});
  }

  p.drawText('Jauge : signal RSRP (dBm)', {x:ML, y:y-oth-11, size:8, font:fI, color:GREY});
  p.drawText('Speedtest : debit DL/UL (Mb/s)', {x:ML+halfW+gap2, y:y-oth-11, size:8, font:fI, color:GREY});
  y -= oth+22;

  // ════════════════════════════════════════════════════════════════
  // PAGE 4 — 3. PLANS + TABLEAU QUALITE + PM TABLE
  // ════════════════════════════════════════════════════════════════
  var r4=newPage(); p=r4.pg; y=r4.y;
  y = sectionTitle(p,y,'3.','Plans du site et points de mesures');
  p.drawText('Note : idealement realisez un point de mesure par zone de 100m2',{x:ML,y:y,size:9,font:fI,color:GREY});y-=16;

  // Afficher tous les plans (multi-étages)
  var allPlans = data.plans && data.plans.length > 0
