    noteLines.forEach(function(l) {
      if (y < 60) { var rn=newPage(); p=rn.pg; y=rn.y; }
      p.drawText(l, {x:ML, y:y, size:9, font:fI, color:GREY, maxWidth:CW}); y-=13;
    });
    y -= 8;
    // Bloc IMPORTANT
    if (y < 100) { var rn=newPage(); p=rn.pg; y=rn.y; }
    p.drawRectangle({x:ML, y:y-38, width:CW, height:42, color:rgb(0.06,0.06,0.15)});
