    p.drawText('Important', {x:ML+10, y:y-8,  size:10, font:fB, color:ORANGE_BT});
    p.drawText('Les antennes Picos emettent exclusivement du reseau mobile 4G, il est donc', {x:ML+10, y:y-20, size:8, font:fR, color:WHITE, maxWidth:CW-14});
