  // ════════════════════════════════════════════════════════════════
  // PAGE 5 — MISE EN PLACE + LOCAL + REPORTING PHOTOS
  // ════════════════════════════════════════════════════════════════
  var r5=newPage(); p=r5.pg; y=r5.y;
  y = sectionTitle(p,y,'','Mise en place de la solution PICO BTS :');
