  if(lpr>0)y-=lpH+10;
  y-=5;

  if(y<150){var rn=newPage();p=rn.pg;y=rn.y;}
  y = subTitle(p,y,'3.2. Reporting photos :');
  p.drawText('Note : prendre des photos suffisamment larges pour retrouver l emplacement des picos.',{x:ML,y:y,size:9,font:fI,color:GREY,maxWidth:CW});y-=16;

  var picoMk = allPlans.flatMap(function(pl){ return (pl.markers||[]).filter(function(m){ return m.type==='pico'; }); });
  for(var pii=0;pii<picoMk.length;pii++){
    var pd=pico[picoMk[pii].label]||{};
    if(!pd.photo)continue;
    if(y<140){var rn=newPage();p=rn.pg;y=rn.y;}
    var pi3=await _embedImg(doc,pd.photo);
    if(!pi3)continue;
    p.drawText(picoMk[pii].label,{x:ML,y:y,size:9,font:fB,color:SOG_BLUE});y-=12;
    var ps=Math.min(CW/2/pi3.width,120/pi3.height);
    p.drawImage(pi3,{x:ML,y:y-120,width:pi3.width*ps,height:pi3.height*ps});y-=130;
  }
  var rphotos=(data.reportingPhotos&&data.reportingPhotos.photos)||[];
  var rpx=ML,rpr=0,rpH=120;
  for(var rpi=0;rpi<rphotos.length;rpi++){
    if(y-rpH<55){var rn=newPage();p=rn.pg;y=rn.y;rpx=ML;rpr=0;}
    var ri=await _embedImg(doc,rphotos[rpi]&&(rphotos[rpi].annotated||rphotos[rpi].src||rphotos[rpi]));
    if(!ri)continue;
    var rs=Math.min((CW/2-10)/ri.width,rpH/ri.height);
    p.drawImage(ri,{x:rpx,y:y-rpH,width:ri.width*rs,height:ri.height*rs});
    rpx+=CW/2+5;rpr++;
    if(rpr>=2){rpx=ML;rpr=0;y-=rpH+10;}
  }
  if(rpr>0)y-=rpH+10;

  // ════════════════════════════════════════════════════════════════
  // PAGE 6 — 4. MISE EN OEUVRE
  // ════════════════════════════════════════════════════════════════
  var r6=newPage(); p=r6.pg; y=r6.y;
  y = sectionTitle(p,y,'4.','Mise en oeuvre :');
  p.drawText('Note : Lister les moyens necessaires au deploiement de la solution.',{x:ML,y:y,size:9,font:fI,color:GREY,maxWidth:CW});y-=16;

  var picoMk2 = allPlans.flatMap(function(pl){ return (pl.markers||[]).filter(function(m){ return m.type==='pico'; }); });
  if(picoMk2.length>0){p.drawText('Installation de '+picoMk2.length+' PICO BTS',{x:ML,y:y,size:10,font:fB,color:BLACK});y-=18;}

  p.drawText('Travaux de dessertes :',{x:ML,y:y,size:10,font:fB,color:BLACK});y-=16;
  var totalCab=0;
  picoMk2.forEach(function(pm3){
    var pd=pico[pm3.label]||{};
    if(pd.cablage||pd.hauteur){
      p.drawText('- Cablage '+pm3.label+' : '+_s2(pd.cablage||'?')+'m, hauteur : '+_s2(pd.hauteur||'?')+'m',{x:ML+10,y:y,size:9,font:fR,color:BLACK});y-=13;
      totalCab+=parseFloat(pd.cablage)||0;
    }
  });
  if(totalCab>0){p.drawText('Total cablage : '+totalCab+'m',{x:ML,y:y,size:10,font:fB,color:SOG_BLUE});y-=18;}
  y-=5;

  p.drawText('Fournitures :',{x:ML,y:y,size:10,font:fB,color:BLACK});y-=14;
  // fournitures est un objet {poe:true, chevilles:false,...}
  var fouLines = [];
  var fouMap = {
    poe:'Injecteur POE', chevilles:'Kit chevilles/vis', colliers:'Colliers de fixation',
    pieceFixation:'Piece de fixation', goulotte:'Goulotte (ml)', bandeau:'Bandeau prises elec.'
  };
  if (oeuvre.fournitures && typeof oeuvre.fournitures === 'object') {
    Object.keys(oeuvre.fournitures).forEach(function(k) {
      if (oeuvre.fournitures[k] && fouMap[k]) fouLines.push(fouMap[k]);
    });
  }
  if (oeuvre.fournituresExtras && _s2(oeuvre.fournituresExtras).trim()) {
    _s2(oeuvre.fournituresExtras).split('\n').forEach(function(l){ if(l.trim()) fouLines.push(l.trim()); });
  }
  if (fouLines.length === 0) {
    fouLines = [picoMk2.length+' x injecteur POE', 'Cablage Ethernet (voir desserte)'];
  }
  fouLines.slice(0,12).forEach(function(l){ p.drawText('- '+_s2(l),{x:ML+10,y:y,size:9,font:fR,color:BLACK,maxWidth:CW-14});y-=12; });
