  p.drawText('Moyens humains :',{x:ML,y:y,size:10,font:fB,color:BLACK});y-=14;
  p.drawText('- Hauteur de travail max  : '+_s2(oeuvre.hauteurTravailMax||'?')+'m',{x:ML+10,y:y,size:9,font:fR,color:BLACK});y-=12;
  p.drawText('- Nombre d intervenants   : '+_s2(oeuvre.nbTechniciens||'2'),{x:ML+10,y:y,size:9,font:fR,color:BLACK});y-=12;
  p.drawText('- Temps de travaux        : '+_s2(oeuvre.nbJours||'1')+' jour',{x:ML+10,y:y,size:9,font:fR,color:BLACK});y-=18;

  p.drawText('Prerequis cote client :',{x:ML,y:y,size:10,font:fB,color:BLACK});y-=14;
  p.drawText('- Besoin de VLAN ?    : '+_s2(oeuvre.vlan||'NON'),{x:ML+10,y:y,size:9,font:fR,color:BLACK});y-=12;
  p.drawText('- Si oui sur quel port ? : '+_s2(oeuvre.vlanPort||'N/A'),{x:ML+10,y:y,size:9,font:fR,color:BLACK});y-=12;
  p.drawText('- Solution validee par ? : '+_s2(oeuvre.validePar||'M. X'),{x:ML+10,y:y,size:9,font:fR,color:BLACK});y-=12;

  // ════════════════════════════════════════════════════════════════
